- (void)segmentControlChanged:(HMSegmentedControl *)sender {
    // Get the current child view controller
    UIViewController *currentViewController = [self.childViewControllers firstObject];

    // Get the new view controller
    UIViewController *newViewController = [self.childViewControllers objectAtIndex:sender.selectedSegmentIndex];

    // Swap the views
    [self.containerView addSubview:newViewController.view];
    [self.containerView addSubview:currentViewController.view];
