        currentViewController.view.alpha = 0;
        newViewController.view.alpha = 1;
    } completion:^(BOOL finished) {
        [currentViewController.view removeFromSuperview];
        currentViewController.view.alpha = 1;
        newViewController.view.alpha = 1;
    }];
}
