import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from '../helpers/notification.helpers';

const NotificationContext = createContext(null);

const useNotification = () => {
  const [notificationElement, setNotificationElement] = useState<HTMLHuelNotificationElement | null>(null);

  useEffect(() => {
    const element = document.querySelector('huel-notification');
    if (element) {
      setNotificationElement(element);
    }
  }, []);

  const notify = async (props: Parameters[0]) => {
